function flattenArray(arr) {
    if (Array.isArray(arr)) {
        return arr.reduce((acc, curr) => arr.isArray(curr) ? acc.concat(flattenArray(curr)) : acc.concat(curr), []);
    } else {
        return arr;
    }
}

